export const createUserProfile = async (user: User, additionalData?: Partial<StudentProfile>): Promise<StudentProfile> => {
    // Basic validation
    if (!user.uid) {
        throw new Error("User ID is missing.");
    }
    if (!user.email) {
        throw new Error("Email is missing.");
    }

    const userDocRef = doc(db, 'students', user.uid);
    const profileData = {
        uid: user.uid,
        email: user.email || null,
        displayName: user.displayName || null,
        photoURL: user.photoURL || null,
        createdAt: serverTimestamp(), // Corrected timestamp
        ...additionalData,
    };

    // Ensure `createdAt` field is properly handled.
    if (!profileData.createdAt) {
        throw new Error("createdAt field is missing.");
